mapper.select:
SELECT l.LOG_ID AS logId, l.ADMIN_ID AS adminId, m.NICKNAME AS adminNickname, l.ACTION_TYPE AS actionType, l.TARGET_TYPE AS targetType, l.TARGET_ID AS targetId, l.BEFORE_VALUE AS beforeValue, l.AFTER_VALUE AS afterValue, TO_CHAR(l.CREATED_AT, 'YYYY-MM-DD HH24:MI') AS createdAt FROM BL_ADMIN_AUDIT_LOGS l LEFT JOIN BL_MEMBERS m ON l.ADMIN_ID = m.MEMBER_ID
AND l.ACTION_TYPE = #{actionType}
AND l.TARGET_TYPE = #{targetType}
AND l.ADMIN_ID = #{adminId}
ORDER BY l.LOG_ID DESC FETCH FIRST #{size} ROWS ONLY
